export const COMPACT_GENERATED_TIMELINE_LOCALE_LOADERS = {
  "es": () => import("./timelineEventBankCompactLocales/es.generated.js"),
  "en": () => import("./timelineEventBankCompactLocales/en.generated.js")
};

const LOCALE_CACHE = new Map();
const LOCALE_PROMISES = new Map();

const normalizeLocaleKey = (locale) => (String(locale || "es").toLowerCase().startsWith("es") ? "es" : "en");

export const loadCompactGeneratedTimelineLocale = async (locale) => {
  const localeKey = normalizeLocaleKey(locale);
  const loader = COMPACT_GENERATED_TIMELINE_LOCALE_LOADERS[localeKey];
  if (!loader) return {};
  if (LOCALE_CACHE.has(localeKey)) return LOCALE_CACHE.get(localeKey) ?? {};
  if (!LOCALE_PROMISES.has(localeKey)) {
    LOCALE_PROMISES.set(localeKey, loader().then((module) => {
      const localeText = module.default ?? {};
      LOCALE_CACHE.set(localeKey, localeText);
      return localeText;
    }));
  }
  return LOCALE_PROMISES.get(localeKey) ?? {};
};
